import React from "react";

export default function StatCard({ title, value, icon: Icon, hint, tone = "sky", className = "" }) {
  const tones = {
    sky: "from-sky-500/20 to-indigo-500/10 text-sky-500 border-sky-500/20 dark:from-sky-500/10 dark:to-indigo-500/5 dark:text-sky-400 dark:border-sky-400/20",
    emerald: "from-emerald-500/20 to-teal-500/10 text-emerald-500 border-emerald-500/20 dark:from-emerald-500/10 dark:to-teal-500/5 dark:text-emerald-400 dark:border-emerald-400/20",
    amber: "from-amber-500/20 to-orange-500/10 text-amber-500 border-amber-500/20 dark:from-amber-500/10 dark:to-orange-500/5 dark:text-amber-400 dark:border-amber-400/20",
    rose: "from-rose-500/20 to-red-500/10 text-rose-500 border-rose-500/20 dark:from-rose-500/10 dark:to-red-500/5 dark:text-rose-400 dark:border-rose-400/20",
    indigo: "from-indigo-500/20 to-purple-500/10 text-indigo-500 border-indigo-500/20 dark:from-indigo-500/10 dark:to-purple-500/5 dark:text-indigo-400 dark:border-indigo-400/20",
  };

  const bgTones = {
    sky: "bg-sky-500 shadow-sky-500/20",
    emerald: "bg-emerald-500 shadow-emerald-500/20",
    amber: "bg-amber-500 shadow-amber-500/20",
    rose: "bg-rose-500 shadow-rose-500/20",
    indigo: "bg-indigo-500 shadow-indigo-500/20",
  };

  return (
    <div className={`group relative rounded-3xl border border-white/40 bg-white/60 p-6 backdrop-blur-xl shadow-[0_8px_30px_rgb(0,0,0,0.04)] transition-all duration-300 hover:-translate-y-1 hover:shadow-[0_8px_30px_rgb(0,0,0,0.08)] dark:border-white/5 dark:bg-slate-900/60 dark:hover:border-white/10 dark:hover:bg-slate-900/80 overflow-hidden ${className}`}>
      <div className={`absolute -right-12 -top-12 h-32 w-32 rounded-full bg-gradient-to-br ${tones[tone]} blur-3xl opacity-50 group-hover:opacity-70 transition-opacity`}></div>
      <div className="relative z-10 flex items-start justify-between">
        <div>
          <p className="text-sm font-bold uppercase tracking-widest text-slate-500 dark:text-slate-400">{title}</p>
          <div className="mt-3 flex items-baseline gap-2">
            <p className="text-4xl font-extrabold tracking-tight text-slate-800 dark:text-white group-hover:scale-105 transition-transform transform origin-left">{value}</p>
          </div>
          {hint ? <p className="mt-2 text-xs font-semibold text-slate-400 dark:text-slate-500">{hint}</p> : null}
        </div>
        <div className={`flex h-12 w-12 items-center justify-center rounded-2xl text-white shadow-lg ${bgTones[tone]} transition-transform duration-300 group-hover:scale-110 group-hover:rotate-3`}>
          {Icon ? <Icon size={20} strokeWidth={2.5} /> : null}
        </div>
      </div>
    </div>
  );
}
