import React from "react";

export default function ChartCard({ title, children, actions, className = "" }) {
  return (
    <section className={`relative rounded-3xl border border-white/40 bg-white/60 p-6 backdrop-blur-xl shadow-[0_8px_30px_rgb(0,0,0,0.04)] dark:border-white/5 dark:bg-slate-900/60 ${className}`}>
      <div className="mb-6 flex items-center justify-between">
        <h3 className="text-sm font-bold uppercase tracking-widest text-slate-500 dark:text-slate-400">{title}</h3>
        <div>{actions}</div>
      </div>
      <div className="relative z-10 w-full">
        {children}
      </div>
    </section>
  );
}
