import React, { useMemo } from "react";
import {
  Bar,
  BarChart,
  Cell,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
  CartesianGrid,
  Line,
  LineChart,
  Area,
  AreaChart,
} from "recharts";
import { FiAlertTriangle, FiArchive, FiLayers, FiMapPin, FiTruck, FiTrendingUp, FiTrendingDown, FiZap, FiPlus } from "react-icons/fi";
import ActivityTimeline from "../components/ActivityTimeline";
import ChartCard from "../components/ChartCard";
import DataTable from "../components/DataTable";
import StatCard from "../components/StatCard";
import StatusBadge from "../components/StatusBadge";
import { useNavigate } from "react-router-dom";

export default function DashboardPage({ tiles, inventory, suppliers, warehouses, transactions, alerts, resolveAlert }) {
  const navigate = useNavigate();
  const totalStock = inventory.reduce((sum, item) => sum + item.quantityInStock, 0);
  const lowStockCount = inventory.filter((item) => item.quantityInStock <= item.reorderLevel).length;
  const activeAlerts = alerts.filter((alert) => alert.status === "open");

  const stockByCategory = useMemo(() => {
    const map = new Map();
    tiles.forEach((tile) => {
      const qty = inventory
        .filter((stock) => stock.tileId === tile.id)
        .reduce((sum, stock) => sum + stock.quantityInStock, 0);
      map.set(tile.category, (map.get(tile.category) || 0) + qty);
    });
    return Array.from(map.entries())
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value);
  }, [tiles, inventory]);

  const monthlyFlow = useMemo(() => {
    const map = new Map();
    transactions.forEach((item) => {
      const month = item.date.slice(0, 7);
      const existing = map.get(month) || { month, stockIn: 0, stockOut: 0 };
      if (item.type === "stock-in") existing.stockIn += item.quantity;
      if (item.type === "stock-out") existing.stockOut += item.quantity;
      map.set(month, existing);
    });
    return Array.from(map.values()).sort((a, b) => a.month.localeCompare(b.month));
  }, [transactions]);

  const topSelling = useMemo(() => {
    const sold = transactions.filter((item) => item.type === "stock-out");
    const map = new Map();
    sold.forEach((item) => {
      map.set(item.tileId, (map.get(item.tileId) || 0) + item.quantity);
    });
    return [...map.entries()]
      .map(([tileId, quantity]) => ({
        tileId,
        quantity,
        name: tiles.find((tile) => tile.id === tileId)?.name || `Tile ${tileId}`,
      }))
      .sort((a, b) => b.quantity - a.quantity)
      .slice(0, 4);
  }, [transactions, tiles]);

  const recentColumns = [
    { key: "date", header: "Date", render: (row) => <span className="font-semibold text-slate-600 dark:text-slate-300">{row.date}</span> },
    { key: "type", header: "Type", render: (row) => <StatusBadge label={row.type} tone={typeTone(row.type)} /> },
    { key: "quantity", header: "Quantity", render: (row) => <span className="font-black">{row.quantity}</span> },
    { key: "performedBy", header: "Performed By" },
  ];

  const timeline = [...transactions]
    .sort((a, b) => b.date.localeCompare(a.date))
    .slice(0, 6)
    .map((item) => ({
      id: item.id,
      action: `${item.type.toUpperCase()} · ${item.quantity} units · ${item.reason}`,
      performedBy: item.performedBy || "System",
      date: item.date,
    }));

  return (
    <div className="space-y-6">
      {/* Top Actions & Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-2 animate-slide-up" style={{ animationDelay: '0.1s' }}>
        <div>
          <h2 className="text-xl font-bold tracking-tight text-slate-800 dark:text-white">Workspace Overview</h2>
          <p className="text-sm text-slate-500 dark:text-slate-400">Your key metrics and insights at a glance.</p>
        </div>
        <div className="flex gap-3">
          <button onClick={() => navigate('/orders')} className="flex items-center gap-2 rounded-xl bg-white/60 dark:bg-slate-800/60 border border-slate-200 dark:border-white/10 px-4 py-2 text-sm font-bold text-slate-700 dark:text-slate-200 shadow-sm backdrop-blur-md transition-all hover:bg-slate-100 hover:scale-105 active:scale-95">
            + Create Order
          </button>
          <button onClick={() => navigate('/tiles')} className="flex items-center gap-2 rounded-xl bg-gradient-to-r from-sky-500 to-indigo-500 px-4 py-2 text-sm font-bold text-white shadow-lg shadow-sky-500/20 transition-all hover:shadow-sky-500/40 hover:scale-105 active:scale-95">
            <FiPlus size={16} />
            Add Tile
          </button>
        </div>
      </div>

      {/* Asymmetric Bento Box Metrics */}
      <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 auto-rows-[140px] animate-slide-up" style={{ animationDelay: '0.2s' }}>
        {/* Dominant Card */}
        <StatCard 
          className="md:col-span-2 lg:col-span-2 row-span-1"
          title="Total Inventory Stock" 
          value={totalStock.toLocaleString()} 
          icon={FiArchive} 
          hint="Total physical units stored across all facilities" 
          tone="sky" 
        />
        <StatCard 
          className="col-span-1"
          title="Total SKUs" 
          value={tiles.length} 
          icon={FiLayers} 
          hint="Active unique tiles" 
          tone="indigo" 
        />
        <StatCard 
          className="col-span-1"
          title="Critical Alerts" 
          value={lowStockCount} 
          icon={FiAlertTriangle} 
          hint="Needs immediate restock" 
          tone="rose" 
        />
        <StatCard 
          className="col-span-1"
          title="Suppliers" 
          value={suppliers.length} 
          icon={FiTruck} 
          tone="emerald" 
        />
        <StatCard 
          className="col-span-1"
          title="Warehouses" 
          value={warehouses.length} 
          icon={FiMapPin} 
          tone="amber" 
        />
        
        {/* Smart Insight Banner */}
        <div className="col-span-1 md:col-span-2 lg:col-span-2 group relative overflow-hidden rounded-3xl border border-indigo-500/20 bg-gradient-to-br from-indigo-500/10 to-purple-500/5 p-6 backdrop-blur-xl transition hover:border-indigo-500/40">
          <div className="absolute top-0 right-0 p-4 opacity-10">
            <FiZap size={100} />
          </div>
          <div className="relative z-10 flex h-full flex-col justify-center">
            <div className="flex items-center gap-2 text-indigo-600 dark:text-indigo-400 font-bold text-sm tracking-widest uppercase mb-2">
              <FiZap className="animate-pulse" /> Smart Insight
            </div>
            <p className="text-xl font-bold text-slate-800 dark:text-slate-100">Ceramic stocks are depleting 15% faster this week.</p>
            <p className="mt-1 text-sm font-medium text-slate-500 dark:text-slate-400">Consider reordering Topazio SKUs before Friday to avoid stockouts.</p>
          </div>
        </div>
      </section>

      {/* Main Content Grid: Insights & Charts */}
      <section className="grid grid-cols-1 xl:grid-cols-3 gap-6 animate-slide-up" style={{ animationDelay: '0.3s' }}>
        
        <div className="xl:col-span-2 space-y-6">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <ChartCard title="Stock By Category" className="h-[340px]">
              <div className="h-56 w-full mt-2">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={stockByCategory} layout="vertical" margin={{ top: 0, right: 30, left: 20, bottom: 0 }}>
                    <XAxis type="number" hide />
                    <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} tick={{ fill: "#64748b", fontSize: 12, fontWeight: 600 }} width={80} />
                    <Tooltip cursor={{ fill: 'transparent' }} />
                    <Bar dataKey="value" radius={[0, 4, 4, 0]} barSize={24}>
                      {stockByCategory.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={`hsl(210, 100%, ${65 - index * 6}%)`} className="transition-all hover:opacity-80" />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </ChartCard>

            <ChartCard title="In vs Out Trend" className="h-[340px]">
              <div className="mb-2 flex items-center gap-4 text-sm font-bold">
                <span className="flex items-center gap-1 text-emerald-500"><div className="h-2 w-2 rounded-full bg-emerald-500"></div> Stock In <FiTrendingUp /></span>
                <span className="flex items-center gap-1 text-amber-500"><div className="h-2 w-2 rounded-full bg-amber-500"></div> Stock Out <FiTrendingDown /></span>
              </div>
              <div className="h-48 w-full mt-2">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={monthlyFlow} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                    <defs>
                      <linearGradient id="colorIn" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                      </linearGradient>
                      <linearGradient id="colorOut" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#f59e0b" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#334155" opacity={0.2} />
                    <XAxis dataKey="month" tick={{ fill: "#64748b", fontSize: 11 }} axisLine={false} tickLine={false} />
                    <YAxis tick={{ fill: "#64748b", fontSize: 11 }} axisLine={false} tickLine={false} />
                    <Tooltip contentStyle={{ background: "#0f172a", border: "none", borderRadius: 12, color: "#fff" }} />
                    <Area type="monotone" dataKey="stockIn" stroke="#10b981" strokeWidth={3} fillOpacity={1} fill="url(#colorIn)" />
                    <Area type="monotone" dataKey="stockOut" stroke="#f59e0b" strokeWidth={3} fillOpacity={1} fill="url(#colorOut)" />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </ChartCard>
          </div>

          <div className="rounded-3xl border border-white/40 bg-white/60 p-6 shadow-[0_8px_30px_rgb(0,0,0,0.04)] backdrop-blur-xl dark:border-white/5 dark:bg-slate-900/60 w-full overflow-hidden relative">
            <div className="absolute -right-24 -bottom-24 h-64 w-64 rounded-full bg-sky-500/10 blur-3xl pointer-events-none"></div>
            <h3 className="mb-4 text-sm font-bold uppercase tracking-widest text-slate-500 dark:text-slate-400">Recent Transactions</h3>
            <DataTable columns={recentColumns} data={[...transactions].sort((a, b) => b.date.localeCompare(a.date))} pageSize={4} />
          </div>
        </div>

        {/* Right Side Panel */}
        <div className="space-y-6 flex flex-col h-full">
          <div className="flex-1 rounded-3xl border border-white/40 bg-white/60 p-6 shadow-[0_8px_30px_rgb(0,0,0,0.04)] backdrop-blur-xl dark:border-white/5 dark:bg-slate-900/60 transition hover:border-white/20">
            <div className="mb-4 flex items-center justify-between">
              <h3 className="text-sm font-bold uppercase tracking-widest text-slate-500 dark:text-slate-400">Hot Items</h3>
              <StatusBadge label="Top Sellers" tone="success" />
            </div>
            <div className="space-y-3">
              {topSelling.length ? (
                topSelling.map((item, i) => (
                  <div key={item.tileId} className="group flex items-center justify-between rounded-2xl bg-white/40 p-3 shadow-sm border border-white/20 transition hover:bg-white dark:bg-white/5 dark:hover:bg-white/10 dark:border-white/5">
                    <div className="flex items-center gap-3">
                      <div className="flex h-8 w-8 items-center justify-center rounded-full bg-slate-100 font-bold text-slate-500 dark:bg-slate-800 dark:text-slate-300">
                        {i + 1}
                      </div>
                      <p className="text-sm font-bold text-slate-800 dark:text-slate-100">{item.name}</p>
                    </div>
                    <span className="rounded-lg bg-sky-100 px-2 py-1 text-xs font-bold text-sky-700 dark:bg-sky-500/20 dark:text-sky-300">
                      {item.quantity} sold
                    </span>
                  </div>
                ))
              ) : (
                <p className="text-sm font-medium text-slate-500 dark:text-slate-400">No sales data.</p>
              )}
            </div>
          </div>

          <div className="flex-1 rounded-3xl border border-white/40 bg-white/60 p-6 shadow-[0_8px_30px_rgb(0,0,0,0.04)] backdrop-blur-xl dark:border-rose-500/20 dark:bg-slate-900/60 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1/2 h-full bg-gradient-to-r from-rose-500/5 to-transparent pointer-events-none"></div>
            <div className="mb-4 flex items-center justify-between relative z-10">
              <h3 className="text-sm font-bold uppercase tracking-widest text-slate-500 dark:text-slate-400">Active Alerts</h3>
              <StatusBadge label={`${activeAlerts.length} issues`} tone={activeAlerts.length ? "danger" : "success"} />
            </div>
            <div className="space-y-3 relative z-10">
              {activeAlerts.length ? (
                activeAlerts.slice(0, 3).map((alert) => {
                  const critical = alert.currentStock <= Math.max(1, Math.floor(alert.reorderLevel * 0.5));
                  return (
                    <div key={alert.id} className={`group rounded-2xl border p-4 transition-all hover:-translate-y-0.5 ${critical ? "border-rose-200 bg-rose-50/80 dark:border-rose-500/30 dark:bg-rose-500/10" : "border-amber-200 bg-amber-50/80 dark:border-amber-500/30 dark:bg-amber-500/10"}`}>
                      <p className="text-sm font-bold text-slate-800 dark:text-white">Tile #{alert.tileId} • Whse #{alert.warehouseId}</p>
                      <div className="mt-2 flex items-center justify-between">
                        <p className={`text-xs font-bold ${critical ? "text-rose-600 dark:text-rose-400": "text-amber-600 dark:text-amber-400"}`}>
                          Stock: {alert.currentStock} / {alert.reorderLevel}
                        </p>
                        <button
                          type="button"
                          onClick={() => resolveAlert(alert.id)}
                          className="rounded-full bg-white/50 px-3 py-1 text-[10px] font-bold uppercase tracking-wider text-slate-700 shadow-sm backdrop-blur transition hover:bg-white dark:bg-slate-800/80 dark:text-slate-300 dark:hover:bg-slate-700"
                        >
                          Resolve
                        </button>
                      </div>
                    </div>
                  );
                })
              ) : (
                <div className="flex h-32 items-center justify-center rounded-2xl border border-emerald-200/50 bg-emerald-50/50 px-4 text-center text-sm font-bold text-emerald-700 dark:border-emerald-500/20 dark:bg-emerald-500/10 dark:text-emerald-400">
                  <FiZap className="mr-2" /> All systems stable.
                </div>
              )}
            </div>
          </div>
        </div>

      </section>
      
      {/* Activity Timeline */}
      <section className="animate-slide-up" style={{ animationDelay: '0.4s' }}>
        <ChartCard title="System Activity Log">
          <ActivityTimeline activities={timeline} />
        </ChartCard>
      </section>
    </div>
  );
}

function typeTone(type) {
  if (type === "stock-in") return "success";
  if (type === "stock-out") return "warning";
  if (type === "damage") return "danger";
  return "info";
}
